async () => {
  const s = (ms) => new Promise(r => setTimeout(r, ms));

  // Navigate to level
  const lvlBtn = document.querySelector('button.level-btn, [id^="level"]') ||
    Array.from(document.querySelectorAll('button')).find(b => /level\s*1/i.test(b.textContent));
  if (lvlBtn) lvlBtn.click();
  await s(400);

  const dlgBtn = document.querySelector('.goal-dialog button');
  if (dlgBtn) dlgBtn.click();
  await s(600);

  const gems = Array.from(document.querySelectorAll('.gem[data-row]'));
  const src = gems.find(g => g.dataset.row === '2' && g.dataset.col === '2');
  const tgt = gems.find(g => g.dataset.row === '2' && g.dataset.col === '3');
  const srcRect = src.getBoundingClientRect();
  const tgtRect = tgt.getBoundingClientRect();
  const fromX = srcRect.x + srcRect.width/2;
  const fromY = srcRect.y + srcRect.height/2;
  const toX = tgtRect.x + tgtRect.width/2;
  const toY = tgtRect.y + tgtRect.height/2;

  const board = document.getElementById('gameBoard');

  // Scenario 1: touchdown + release within 50ms → no dim at all
  board.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  await s(30);
  const s1_at30 = document.querySelectorAll('.gem.swap-dimmed').length;
  board.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  await s(200);
  const s1_after_release = document.querySelectorAll('.gem.swap-dimmed').length;

  // Scenario 2: touchdown + wait 150ms → initial dim applied
  board.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  await s(150);
  const s2_at150 = document.querySelectorAll('.gem.swap-dimmed').length;
  board.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  await s(200);

  // Scenario 3: touchdown + quickly drag to target within 50ms → immediate preview dim
  board.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  await s(20);
  board.dispatchEvent(new MouseEvent('mousemove', { bubbles: true, cancelable: true, clientX: toX, clientY: toY, button: 0 }));
  // Check immediately - should be fully dimmed without waiting 100ms
  const s3_imm = document.querySelectorAll('.gem.swap-dimmed').length;
  const s3_preview = document.querySelectorAll('.gem.preview').length;
  board.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, clientX: toX, clientY: toY, button: 0 }));
  await s(400);

  return {
    s1_tap_release_quick: { at30ms_dimmed: s1_at30, after_release: s1_after_release },
    s2_hold_150ms: { dimmed_at_150ms: s2_at150 },
    s3_quick_drag_to_target: { dimmed_immediate: s3_imm, preview_count: s3_preview },
  };
}

