async () => {
  const s = (ms) => new Promise(r => setTimeout(r, ms));

  // Navigate to level 1
  const lvlBtn = Array.from(document.querySelectorAll('button')).find(b => /level\s*1/i.test(b.textContent));
  if (lvlBtn) lvlBtn.click();
  await s(500);
  const dlgBtn = document.querySelector('.goal-dialog button');
  if (dlgBtn) dlgBtn.click();
  await s(600);

  const gems = Array.from(document.querySelectorAll('.gem[data-row]'));
  const src = gems.find(g => g.dataset.row === '2' && g.dataset.col === '2');
  const tgt = gems.find(g => g.dataset.row === '2' && g.dataset.col === '3');
  if (!src || !tgt) return { err: 'no board' };

  const srcRect = src.getBoundingClientRect();
  const tgtRect = tgt.getBoundingClientRect();
  const fromX = srcRect.x + srcRect.width/2;
  const fromY = srcRect.y + srcRect.height/2;
  const toX = tgtRect.x + tgtRect.width/2;
  const toY = tgtRect.y + tgtRect.height/2;
  const board = document.getElementById('gameBoard');

  const countDim = () => document.querySelectorAll('.gem.swap-dimmed').length;

  // S1: pure tap + release (no movement)
  board.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  const s1_t0 = countDim();
  await s(200);
  const s1_t200 = countDim();
  board.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  await s(200);
  const s1_after = countDim();

  // S2: hold with no movement for 500ms → still no dim
  board.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  await s(500);
  const s2_t500 = countDim();
  board.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  await s(200);

  // S3: tap then move off source to non-adjacent (non-valid target) → initial dim
  board.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  await s(30);
  // Move to a far non-adjacent tile (0,0)
  const farGem = gems.find(g => g.dataset.row === '0' && g.dataset.col === '0');
  const farRect = farGem.getBoundingClientRect();
  board.dispatchEvent(new MouseEvent('mousemove', { bubbles: true, cancelable: true, clientX: farRect.x + farRect.width/2, clientY: farRect.y + farRect.height/2, button: 0 }));
  await s(10);
  const s3_after_move = countDim();
  board.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, clientX: farRect.x + farRect.width/2, clientY: farRect.y + farRect.height/2, button: 0 }));
  await s(200);

  // S4: tap then quick drag to adjacent valid target → preview dim immediate
  board.dispatchEvent(new MouseEvent('mousedown', { bubbles: true, cancelable: true, clientX: fromX, clientY: fromY, button: 0 }));
  await s(20);
  board.dispatchEvent(new MouseEvent('mousemove', { bubbles: true, cancelable: true, clientX: toX, clientY: toY, button: 0 }));
  const s4_after_move = countDim();
  const s4_preview = document.querySelectorAll('.gem.preview').length;
  board.dispatchEvent(new MouseEvent('mouseup', { bubbles: true, cancelable: true, clientX: toX, clientY: toY, button: 0 }));
  await s(500);

  return {
    S1_pure_tap: { at0: s1_t0, at200: s1_t200, after_release: s1_after },
    S2_long_hold_no_movement: { at500: s2_t500 },
    S3_move_off_to_invalid: { dimmed: s3_after_move },
    S4_fast_drag_to_valid: { dimmed: s4_after_move, preview: s4_preview },
  };
}

